parameters.functionCode:
// Extract email data from webhook
const emailData = items[0].json;

// Validate required fields
if (!emailData.to || !emailData.subject) {
  throw new Error('Missing required fields: to and subject');
}

// Format for email sending
return [{
  json: {
    to: emailData.to,
    subject: emailData.subject,
    body: emailData.body || emailData.text || '',
    from: emailData.from || 'noreply@yourdomain.com',
    html: emailData.html || null
  }
}];

